import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - nextGeneration", () => {
  // Degenerate base case
  it.todo("should return [] for an empty input (no living cells)");

  // Rule 1 - Underpopulation
  it.todo("should kill a single isolated cell with 0 neighbors — [(0,0)] → []");
  it.todo("should kill two adjacent cells each with 1 neighbor (underpopulation) — [(0,1),(1,1)] → []");

  // Block still life (survival with 3 neighbors each)
  it.todo("should keep a 2x2 block unchanged (still life) — [(0,0),(1,0),(0,1),(1,1)] → same set");

  // Rule 2 - Survival
  it.todo("should let center cell (1,1) survive when it has 3 live neighbors (top-row + bottom-center) — Rule 2");

  // Rule 4 - Reproduction
  it.todo("should bring dead cell (1,1) to life when it has exactly 3 live neighbors (L-shape) — Rule 4: [(0,0),(1,0),(0,1)] produces (1,1) alive");

  // Rule 3 - Overpopulation
  it.todo("should kill center cell (1,1) with 4 live neighbors (full 3x3 ring + center) — Rule 3");

  // Blinker oscillator - vertical to horizontal
  it.todo("should oscillate a vertical blinker into a horizontal one — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");

  // Negative coordinates
  it.todo("should handle negative coordinates correctly (blinker output contains (-1,1) — verifies infinite grid in negative direction)");
});
